import {
  useRef,
  useState,
  useEffect,
  useImperativeHandle,
  Children,
  isValidElement,
} from "react";
import { cn } from "../../lib/utils";
import { SynchronizeIcon } from "../../icons/Synchronize";
import { CardProps, CardHeaderProps } from "../../types/card";

/**
 * Card component
 *
 * A container component that represents information in the form of a tile
 * with separate header, content, and footer areas. Supports loading states
 * with delayed indicator display.
 *
 * This implementation provides full UI5 Card feature parity plus an optional
 * footer slot for action buttons (aligned right).
 *
 * @example
 * ```tsx
 * // Basic card with header and content
 * <Card
 *   header={
 *     <CardHeader
 *       titleText="Product Details"
 *       subtitleText="SKU: 12345"
 *     />
 *   }
 * >
 *   <CardContent>
 *     <p>Product description and details...</p>
 *   </CardContent>
 * </Card>
 *
 * // Card with interactive header (card automatically detects and applies hover styles)
 * <Card
 *   header={
 *     <CardHeader
 *       titleText="Click Me"
 *       subtitleText="Interactive header with hover effects"
 *       interactive
 *       onClick={() => console.log('clicked')}
 *     />
 *   }
 * >
 *   <CardContent>
 *     <p>Card border shows hover state, header background shows hover state</p>
 *   </CardContent>
 * </Card>
 *
 * // Card with footer actions
 * <Card
 *   header={<CardHeader titleText="Edit Profile" />}
 *   footer={
 *     <CardFooter>
 *       <Button design="Tertiary">Cancel</Button>
 *       <Button design="Primary">Save</Button>
 *     </CardFooter>
 *   }
 * >
 *   <CardContent>
 *     <Input placeholder="Name" />
 *   </CardContent>
 * </Card>
 *
 * // Loading state
 * <Card loading accessibleName="Loading product data">
 *   <CardContent>Content loading...</CardContent>
 * </Card>
 * ```
 */
export function Card({
      children,
      header,
      footer,
      toolbar,
      toolbarVisible,
      toolbarClassName,
      loading = false,
      loadingDelay = 1000,
      accessibleName,
      accessibleNameRef,
      accessibleDescriptionRef,
      className,
      style,
      id,
      "data-testid": dataTestId,
      onMouseEnter,
      onMouseLeave,
      onMouseDown,
      onMouseUp,
      onClick,
      onFocus,
      onBlur,
      ref,
    }: CardProps) {
    const cardRef = useRef<HTMLDivElement>(null);
    const [showLoading, setShowLoading] = useState(false);

    // Detect if header is interactive by checking its props
    const isHeaderInteractive =
      isValidElement<CardHeaderProps>(header) && header.props.interactive === true;

    // Handle loading delay
    useEffect(() => {
      if (!loading) {
        setShowLoading(false);
        return;
      }

      // If no delay, show immediately
      if (loadingDelay <= 0) {
        setShowLoading(true);
        return;
      }

      // Set up delayed loading indicator
      const timer = setTimeout(() => {
        setShowLoading(true);
      }, loadingDelay);

      return () => clearTimeout(timer);
    }, [loading, loadingDelay]);

    // Expose imperative methods
    useImperativeHandle(
      ref,
      () => ({
        focus() {
          cardRef.current?.focus();
        },
        blur() {
          cardRef.current?.blur();
        },
        get nativeElement() {
          return cardRef.current;
        },
      }),
      []
    );

    // Detect no-content state (Gap #9)
    const hasContent =
      children != null &&
      children !== false &&
      children !== "" &&
      Children.count(children) > 0;

    const card = (
      <article
        ref={cardRef}
        id={id}
        role="region"
        aria-roledescription="Card"
        aria-label={accessibleName}
        aria-labelledby={accessibleNameRef}
        aria-describedby={accessibleDescriptionRef}
        aria-busy={loading || undefined}
        className={cn(
          "relative rounded-[8px] border border-sapphire-border-primary bg-sapphire-card-bg-primary text-sapphire-text-primary",
          "flex flex-col",
          isHeaderInteractive && [
            // Only transition border and shadow, not outline (focus should be instant)
            "transition-[border-color,box-shadow] duration-200",
            // Focus ring on the card when header is focused (using outline to avoid layout shift)
            "focus-within:outline focus-within:outline-2 focus-within:outline-sapphire-border-focus focus-within:outline-offset-[-2px]",
            // Hover state
            "hover:border-sapphire-border-active hover:shadow-[0px_1px_2px_0px_rgba(10,10,10,0.25)]",
          ],
          !hasContent && "card--nocontent",
          // When no content/footer, make header corners fully rounded
          !hasContent && !footer && "[&>*:first-child]:rounded-[8px]",
          className
        )}
        style={style}
        data-testid={dataTestId}
        data-part="root"
        onMouseEnter={onMouseEnter}
        onMouseLeave={onMouseLeave}
        onMouseDown={onMouseDown}
        onMouseUp={onMouseUp}
        onClick={onClick}
        onFocus={onFocus}
        onBlur={onBlur}
      >
        {/* Header slot */}
        {header}

        {/* Content area — only rendered when there is content */}
        {hasContent && (
          <div
            className="flex-1 relative overflow-hidden"
            role="group"
            aria-label="Card Content"
            data-part="content"
          >
            {children}

            {/* Loading overlay */}
            {showLoading && (
              <div
                className={cn(
                  "absolute inset-0",
                  "bg-sapphire-background-primary/80 backdrop-blur-sm",
                  "flex items-center justify-center",
                  "z-10"
                )}
                aria-hidden="true"
              >
                <SynchronizeIcon className="h-8 w-8 animate-spin text-sapphire-text-tertiary" />
              </div>
            )}
          </div>
        )}

        {/* Footer slot */}
        {footer}
      </article>
    );

    // When toolbar is present, wrap in a hover-detection container.
    // Toolbar is absolutely positioned above the card with a 12 px
    // overlap (translate-y-3).  Uses invisible / visible so the card
    // never shifts — the toolbar simply pops into view.
    if (toolbar) {
      return (
        <div className="relative group/card" data-part="card-toolbar-wrapper">
          <div
            className={cn(
              "absolute bottom-full left-0 right-0 z-10 translate-y-3",
              !toolbarVisible && "invisible group-hover/card:visible",
            )}
            data-part="toolbar"
          >
            <div
              className={cn(
                "flex items-center justify-center gap-px p-1",
                "bg-sapphire-card-bg-primary border border-brand-purple rounded-[8px]",
                "shadow-[0px_4px_10px_0px_rgba(10,10,10,0.15),0px_2px_5px_0px_rgba(10,10,10,0.05)]",
                toolbarClassName
              )}
            >
              {toolbar}
            </div>
          </div>
          {card}
        </div>
      );
    }

    return card;
  }
